mapper.select:
SELECT ba.id, ba.title, ba.summary, ba.create_time, ba.modify_time, su.username, ba.view, ba.favorite, ba.is_recommend AS recommend FROM blog_article ba LEFT JOIN sys_user su ON su.id = ba.user_id
ba.is_deleted = 0
AND ba.title LIKE CONCAT('%', #{dto.title, jdbcType=VARCHAR}, '%')
AND ba.is_recommend = #{dto.recommend, jdbcType=INTEGER}
ORDER BY ${dto.sortCondition}

SELECT ba.id, su.username AS author, ba.title, ba.summary, ba.markdown_content, ba.type_id, ba.create_time, ba.modify_time, ba.view, ba.favorite, ba.is_recommend AS recommend, ba.is_draft AS draft, ba.cover_url FROM blog_article ba LEFT JOIN sys_user su ON su.id = ba.user_id
ba.is_delete = 0
AND ba.id = #{dto.id, jdbcType=INTEGER}
